# boss-reach decks vs early-died decks. Cards that empirically correlate with
# reaching the boss get a positive bonus (capped ±1.5). Re-run that script
# whenever the policy or strategy shifts substantially to refresh the data.
_EMPIRICAL_PATH = _os.path.join(_os.path.dirname(_os.path.abspath(__file__)),
                                 "..", "data", "card_empirical.json")
try:
    with open(_EMPIRICAL_PATH) as _ef:
        EMPIRICAL_BONUS = _json.load(_ef)
except (FileNotFoundError, ValueError):
    EMPIRICAL_BONUS = {}

