# Type-based generic scoring weights
ATTACK_DPE_BASELINE = 6.0   # Strike: 6 dmg / 1 cost
BLOCK_BPE_BASELINE = 5.0    # Defend: 5 block / 1 cost
DRAW_VALUE = 2.5            # per card drawn — Run 22 verified (3.0 caused regression in Run 24)
ENERGY_VALUE = 5.0          # per energy generated — Run 22 verified
LOW_COST_BONUS = 0.0        # 0-cost universal bonus — disabled after Run 24 showed
                            # avg_floor 14.3→11.2 regression. The bonus pulled the policy
                            # toward cheap utility cards at expense of damage. Re-enable
                            # only with stronger filtering (e.g. only when paired with draw/energy).
ONE_COST_BONUS = 0.0
VULN_WEAK_VALUE = 1.5       # vulnerable or weak bonus
STRENGTH_VALUE = 2.5        # per point of strength
DEXTERITY_VALUE = 2.0       # per point of dexterity
EXHAUST_VALUE = 1.0         # exhaust synergy bonus
AOE_VALUE = 1.5             # AOE bonus
POWER_BONUS = 1.5           # powers persist, extra value
RARITY_BONUS = {"Common": 0.0, "Uncommon": 0.5, "Rare": 1.0}

# Threshold above which an un-upgraded card should be a SMITH target at the next
# rest site. Calibrated so DEMON_FORM/BARRICADE/HOWL_FROM_BEYOND/LIMIT_BREAK and
# top draw/energy enablers (OFFERING/SHRUG_IT_OFF/POMMEL_STRIKE) all qualify, but
# common Strike/Defend variants do not.
SMITH_PRIORITY_THRESHOLD = 7.0

# Cards that are never worth picking (status/curse starters)
SKIP_IDS = {"STRIKE_R", "DEFEND_R", "STRIKE_B", "DEFEND_B", "STRIKE_G",
            "DEFEND_G", "WOUND", "DAZE", "SLIMED", "BURN", "DECAY",
            # STS2 naming variants
            "STRIKE_IRONCLAD", "DEFEND_IRONCLAD",
            "STRIKE_SILENT", "DEFEND_SILENT",
            "STRIKE_DEFECT", "DEFEND_DEFECT",
            # STS2 curses/status cards
            "DOUBT", "REGRET", "SHAME", "VOID", "NORMALITY"}


def score_card(card: dict) -> float:
    """Score a card 0-10 based on its effectiveness.

    card: dict with keys: id, cost, type, rarity, stats, name, keywords
    """
    card_id = card.get("id", "")
    if isinstance(card_id, dict):
        card_id = card_id.get("en", str(card_id))
    card_id = card_id.upper().strip()
    # Game prefixes IDs with "CARD." — strip it for override lookups
    if card_id.startswith("CARD."):
        card_id = card_id[5:]

    # Check manual override first — but DO still apply empirical bonus below
    # so the data-driven signal can nudge override values up/down.
    if card_id in OVERRIDES:
        score = OVERRIDES[card_id]
        if EMPIRICAL_BONUS and card_id in EMPIRICAL_BONUS:
            _eb = EMPIRICAL_BONUS[card_id]
            if abs(_eb) >= EMPIRICAL_MIN_MAGNITUDE:
                score += _eb * EMPIRICAL_WEIGHT
        return max(0.0, min(score, 10.0))

    # Skip status/curse cards
    if card_id in SKIP_IDS:
        return 0.0

    raw_cost = card.get("cost", 1)
    if not isinstance(raw_cost, (int, float)):
        raw_cost = 1
    cost = max(raw_cost, 1)  # treat 0-cost as 1 for ratio calc
    ctype = (card.get("type") or "").lower()
    rarity = card.get("rarity", "Common")
    stats = card.get("stats") or {}
    name = card.get("name", "")
    if isinstance(name, dict):
        name = name.get("en", "")

    score = 0.0
    # Low-cost combo bonus — 0-cost cards stack in high-energy turns,
    # 1-cost cards still cycle cheaply. Boss wins correlate with playing
    # many cards per turn, and cost is the gate.
    if raw_cost == 0:
        score += LOW_COST_BONUS
    elif raw_cost == 1:
        score += ONE_COST_BONUS

    # === Attack cards: score by damage per energy ===
    if ctype == "attack":
        damage = stats.get("damage", 0)
        if damage > 0:
            dpe = damage / cost
            score += min(dpe / ATTACK_DPE_BASELINE * 5.0, 7.0)

    # === Skill cards: score by block, draw, energy ===
    elif ctype == "skill":
        block = stats.get("block", 0)
        if block > 0:
            bpe = block / cost
            score += min(bpe / BLOCK_BPE_BASELINE * 4.0, 5.0)

    # === Power cards: base value + effect scoring ===
    elif ctype == "power":
        score += POWER_BONUS
        # Powers with str/dex are very strong
        if "strength" in str(stats).lower() or "str" in str(stats).lower():
            score += STRENGTH_VALUE
        if "dexterity" in str(stats).lower() or "dex" in str(stats).lower():
            score += DEXTERITY_VALUE

    # === Generic bonuses ===
    # Draw value
    draw = stats.get("draw", 0)
    if draw > 0:
        score += draw * DRAW_VALUE

    # Energy generation
    energy = stats.get("energy", 0)
    if energy > 0:
        score += energy * ENERGY_VALUE

    # Block on any card (not just skills)
    if ctype != "skill":
        block = stats.get("block", 0)
        if block > 0:
            score += min(block / cost * 0.5, 3.0)

    # Damage on non-attack cards
    if ctype != "attack":
        damage = stats.get("damage", 0)
        if damage > 0:
            score += min(damage / cost * 0.5, 3.0)

    # Check keywords/description for effects
    desc = str(card.get("description", "")).lower()
    if "vulnerable" in desc:
        score += VULN_WEAK_VALUE
    if "weak" in desc:
        score += VULN_WEAK_VALUE
    if "strength" in desc and ctype != "power":
        score += STRENGTH_VALUE * 0.5
    if "exhaust" in desc:
        score += EXHAUST_VALUE
    if "all enem" in desc:
        score += AOE_VALUE
    if "draw" in desc and draw == 0:
        score += DRAW_VALUE  # draw mentioned but not in stats

    # Rarity bonus
    score += RARITY_BONUS.get(rarity, 0.0)

    # Empirical bonus from boss-reach correlation data
    if EMPIRICAL_BONUS and card_id in EMPIRICAL_BONUS:
        score += EMPIRICAL_BONUS[card_id] * EMPIRICAL_WEIGHT

    # Clamp to 0-10
    return max(0.0, min(score, 10.0))


def best_smith_target(deck: list[dict]) -> int | None:
    """Index in `deck` of the highest-value un-upgraded card worth a SMITH.

    Returns None if no card in the deck scores >= SMITH_PRIORITY_THRESHOLD when
    un-upgraded. Used by rest_site_action to override the default heal-vs-smith
    HP threshold: there's no point healing 5 HP if a key DEMON_FORM is sitting
    un-upgraded — upgrading it pays off across every remaining combat.
    """
    if not deck:
        return None
    best_idx, best_score = None, -1.0
    for i, c in enumerate(deck):
        if c.get("upgraded"):
            continue
        s = score_card(c)
        if s >= SMITH_PRIORITY_THRESHOLD and s > best_score:
            best_idx, best_score = i, s
    return best_idx


# --- Deck-archetype synergy ---------------------------------------------
# Cards that GIVE strength (a Strength build wants more attacks).
STRENGTH_GAIN_CARDS = {"DEMON_FORM", "INFLAME", "LIMIT_BREAK", "SPOT_WEAKNESS",
                       "FLEX", "RUPTURE", "FEROCITY", "BRIMSTONE",
                       "BLADE_OF_INK", "DOMINATE", "SETUP_STRIKE"}
# Cards that BENEFIT FROM strength (they scale per-hit).
STRENGTH_USER_CARDS = {"HEAVY_BLADE", "PUMMEL", "TWIN_STRIKE", "WHIRLWIND",
                       "FIEND_FIRE", "ANGER", "SWORD_BOOMERANG",
                       "BLUDGEON", "PERFECTED_STRIKE", "BEAT_DOWN", "GRAPPLE",
                       "POMMEL_STRIKE", "DISMANTLE", "DROPKICK"}
# Cards that EXHAUST (enable exhaust archetype).
EXHAUST_PAYLOAD_CARDS = {"FEEL_NO_PAIN", "DARK_EMBRACE", "CORRUPTION",
                         "FIRE_BREATHING", "SENTINEL", "JUGGERNAUT",
                         "FORGOTTEN_RITUAL", "ASHEN_STRIKE", "EVIL_EYE"}
# Cards that GET EXHAUSTED naturally (fuel for exhaust payload).
EXHAUST_FUEL_CARDS = {"TRUE_GRIT", "SECOND_WIND", "OFFERING", "SEVER_SOUL",
                      "FIEND_FIRE", "REAPER", "OBLITERATE", "CARNAGE"}
# Cards that scale with block (Block archetype).
BLOCK_PAYLOAD_CARDS = {"BARRICADE", "JUGGERNAUT", "ENTRENCH", "BODY_SLAM",
                       "GRAPPLE", "METALLICIZE", "SECOND_WIND"}


def _card_id_norm(card: dict) -> str:
    cid = card.get("id", "")
    if isinstance(cid, dict): cid = cid.get("en", str(cid))
    cid = str(cid).upper().strip()
    if cid.startswith("CARD."): cid = cid[5:]
    return cid


def compute_deck_archetype(deck: list[dict]) -> dict:
    """Count synergy markers in the deck. Used to bias card picks toward what
    the deck is becoming. Returns counts (not bools) so downstream code can
    weight by saturation (one Inflame is good; three is overkill)."""
    if not deck:
        return {"str_gain": 0, "str_user": 0, "exhaust_payload": 0,
                "exhaust_fuel": 0, "block_payload": 0, "n": 0}
    counts = {"str_gain": 0, "str_user": 0, "exhaust_payload": 0,
              "exhaust_fuel": 0, "block_payload": 0, "n": len(deck)}
    for c in deck:
        cid = _card_id_norm(c)
        if cid in STRENGTH_GAIN_CARDS: counts["str_gain"] += 1
        if cid in STRENGTH_USER_CARDS: counts["str_user"] += 1
        if cid in EXHAUST_PAYLOAD_CARDS: counts["exhaust_payload"] += 1
        if cid in EXHAUST_FUEL_CARDS: counts["exhaust_fuel"] += 1
        if cid in BLOCK_PAYLOAD_CARDS: counts["block_payload"] += 1
    return counts


def score_card_in_deck(card: dict, deck: list[dict]) -> float:
    """Score a card with deck-context bonuses. Reward cards that fit the
    archetype the deck is building toward; lightly penalize redundant payloads."""
    base = score_card(card)
    if not deck:
        return base
    cid = _card_id_norm(card)
    arch = compute_deck_archetype(deck)
    bonus = 0.0

    # Strength archetype: if deck has 1+ str_gain, str_user cards become more valuable.
    if arch["str_gain"] >= 1 and cid in STRENGTH_USER_CARDS:
        bonus += 1.0
    # Reverse: if deck has 2+ str_users (commits to strength), str_gain becomes more valuable.
    if arch["str_user"] >= 2 and cid in STRENGTH_GAIN_CARDS:
        bonus += 1.0

    # Exhaust archetype: payload + fuel synergy.
    if arch["exhaust_payload"] >= 1 and cid in EXHAUST_FUEL_CARDS:
        bonus += 0.7
    if arch["exhaust_fuel"] >= 2 and cid in EXHAUST_PAYLOAD_CARDS:
        bonus += 1.2

    # Block archetype: stack block payloads only if deck commits to defense.
    if arch["block_payload"] >= 1 and cid in BLOCK_PAYLOAD_CARDS:
        bonus += 0.5

    # Saturation penalty — three Inflames is one too many.
    if cid in STRENGTH_GAIN_CARDS and arch["str_gain"] >= 2:
        bonus -= 1.5
    if cid in EXHAUST_PAYLOAD_CARDS and arch["exhaust_payload"] >= 2:
        bonus -= 1.0

    return max(0.0, min(base + bonus, 10.0))


def deck_quality_score(deck: list[dict]) -> float:
    """Average score of the top-10 cards in the deck. Used as a milestone reward
    proxy: a deck whose top-10 averages 6+ is in good shape; below 4.5 is weak."""
    if not deck:
        return 0.0
    scores = sorted((score_card(c) for c in deck), reverse=True)[:10]
    return sum(scores) / len(scores) if scores else 0.0


def pick_best_card(cards: list[dict], threshold: float = 3.5,
                   deck: list[dict] = None) -> int | None:
    """Return index of the best card above threshold, or None to skip.
    If `deck` is provided, uses deck-aware scoring (synergy bonuses)."""
    if not cards:
        return None
    scorer = (lambda c: score_card_in_deck(c, deck)) if deck else score_card
    scored = [(i, scorer(c)) for i, c in enumerate(cards)]
    scored.sort(key=lambda x: x[1], reverse=True)
    best_idx, best_score = scored[0]
    if best_score >= threshold:
        return best_idx
    return None


def pick_worst_card(cards: list[dict], threshold: float = 5.0) -> int | None:
    """Return index of the worst card below threshold for removal, or None."""
    if not cards:
        return None
    scored = [(i, score_card(c)) for i, c in enumerate(cards)]
    scored.sort(key=lambda x: x[1])
    worst_idx, worst_score = scored[0]
    if worst_score < threshold:
        return worst_idx
    return None
